package wpam

import (
	"socialpredict/models"
	"time"
)

const (
	wpamOutcomeYes = "YES"
	wpamOutcomeNo  = "NO"
)

type ProbabilityChange struct {
	Probability float64   `json:"probability"`
	Timestamp   time.Time `json:"timestamp"`
}

type ProjectedProbability struct {
	Probability float64 `json:"projectedprobability"`
}

type ProbabilityFormula interface {
	Calculate(seeds Seeds, totalYes, totalNo int64) float64
}

// Seeds captures the initial market parameters needed for WPAM calculations.
type Seeds struct {
	InitialProbability     float64
	InitialSubsidization   int64
	InitialYesContribution int64
	InitialNoContribution  int64
}

// SeedProvider supplies seeds for probability calculations.
type SeedProvider interface {
	Seeds() Seeds
}

// StaticSeedProvider returns a fixed seed configuration.
type StaticSeedProvider struct {
	Value Seeds
}

func (p StaticSeedProvider) Seeds() Seeds { return p.Value }

type marketContributions struct {
	yes int64
	no  int64
}

type contributionAccumulator func(*marketContributions, int64)

type weightedAverageProbabilityFormula struct{}

var defaultSeedProvider = StaticSeedProvider{
	Value: Seeds{
		InitialProbability:   0.5,
		InitialSubsidization: 1,
	},
}

var defaultContributionAccumulators = map[string]contributionAccumulator{
	wpamOutcomeYes: func(contributions *marketContributions, amount int64) { contributions.yes += amount },
	wpamOutcomeNo:  func(contributions *marketContributions, amount int64) { contributions.no += amount },
}

// ProbabilityCalculator performs WPAM probability calculations using supplied seeds.
type ProbabilityCalculator struct {
	seeds        SeedProvider
	formula      ProbabilityFormula
	accumulators map[string]contributionAccumulator
}

// NewProbabilityCalculator constructs a calculator with the provided seed source.
// If provider is nil, sensible defaults are used.
func NewProbabilityCalculator(provider SeedProvider) ProbabilityCalculator {
	if provider == nil {
		provider = defaultSeedProvider
	}
	return ProbabilityCalculator{
		seeds:        provider,
		formula:      weightedAverageProbabilityFormula{},
		accumulators: defaultContributionAccumulators,
	}
}

// Seeds returns the configured seeds for the calculator.
func (c ProbabilityCalculator) Seeds() Seeds {
	return c.withDefaults().seeds.Seeds()
}

// CalculateMarketProbabilitiesWPAM calculates and returns the probability changes based on bets.
func CalculateMarketProbabilitiesWPAM(marketCreatedAtTime time.Time, bets []models.Bet) []ProbabilityChange {
	return NewProbabilityCalculator(nil).CalculateMarketProbabilitiesWPAM(marketCreatedAtTime, bets)
}

// CalculateMarketProbabilitiesWPAM calculates and returns the probability changes based on bets using the calculator seeds.
func (c ProbabilityCalculator) CalculateMarketProbabilitiesWPAM(marketCreatedAtTime time.Time, bets []models.Bet) []ProbabilityChange {
	calculator := c.withDefaults()
	seeds := calculator.seeds.Seeds()
	var probabilityChanges []ProbabilityChange

	P_initial := seeds.InitialProbability

	probabilityChanges = append(probabilityChanges, ProbabilityChange{Probability: P_initial, Timestamp: marketCreatedAtTime})

	// Calculate probabilities after each bet
	contributions := marketContributions{
		yes: seeds.InitialYesContribution,
		no:  seeds.InitialNoContribution,
	}
	for _, bet := range bets {
		calculator.applyContribution(&contributions, bet)

		newProbability := calculator.formula.Calculate(seeds, contributions.yes, contributions.no)
		probabilityChanges = append(probabilityChanges, ProbabilityChange{Probability: newProbability, Timestamp: bet.PlacedAt})
	}

	return probabilityChanges
}

func ProjectNewProbabilityWPAM(marketCreatedAtTime time.Time, currentBets []models.Bet, newBet models.Bet) ProjectedProbability {
	return NewProbabilityCalculator(nil).ProjectNewProbabilityWPAM(marketCreatedAtTime, currentBets, newBet)
}

// ProjectNewProbabilityWPAM projects the probability after a new bet using calculator seeds.
func (c ProbabilityCalculator) ProjectNewProbabilityWPAM(marketCreatedAtTime time.Time, currentBets []models.Bet, newBet models.Bet) ProjectedProbability {
	updatedBets := append(append([]models.Bet(nil), currentBets...), newBet)
	probabilityChanges := c.withDefaults().CalculateMarketProbabilitiesWPAM(marketCreatedAtTime, updatedBets)
	finalProbability := probabilityChanges[len(probabilityChanges)-1].Probability

	return ProjectedProbability{Probability: finalProbability}
}

func (c ProbabilityCalculator) withDefaults() ProbabilityCalculator {
	if c.seeds == nil {
		c.seeds = defaultSeedProvider
	}
	if c.formula == nil {
		c.formula = weightedAverageProbabilityFormula{}
	}
	if c.accumulators == nil {
		c.accumulators = defaultContributionAccumulators
	}
	return c
}

func (c ProbabilityCalculator) applyContribution(contributions *marketContributions, bet models.Bet) {
	if accumulate, ok := c.accumulators[bet.Outcome]; ok {
		accumulate(contributions, bet.Amount)
	}
}

func (weightedAverageProbabilityFormula) Calculate(seeds Seeds, totalYes, totalNo int64) float64 {
	return (seeds.InitialProbability*float64(seeds.InitialSubsidization) + float64(totalYes)) /
		(float64(seeds.InitialSubsidization) + float64(totalYes) + float64(totalNo))
}

package marketmath

import (
	"socialpredict/models"
	"sort"
)

// SellDustCalculator defines how to compute dust for a sell bet.
type SellDustCalculator interface {
	DustForSell(sellBet models.Bet, allBets []models.Bet) int64
}

// ConstantSellDustCalculator returns a fixed dust amount for every sell.
type ConstantSellDustCalculator struct {
	DustPerSell int64
}

func (c ConstantSellDustCalculator) DustForSell(sellBet models.Bet, allBets []models.Bet) int64 {
	if sellBet.Amount < 0 {
		return c.DustPerSell
	}
	return 0
}

var defaultSellDustCalculator = ConstantSellDustCalculator{DustPerSell: 1}

// GetMarketVolumeWithDust returns the market volume including accumulated dust from selling
// This ensures currency conservation by accounting for dust that remains in the market
func GetMarketVolumeWithDust(bets []models.Bet) int64 {
	baseVolume := GetMarketVolume(bets)
	dustVolume := calculateDustStack(bets)
	return baseVolume + dustVolume
}

// calculateDustStack computes total dust accumulated from all sell transactions
// Uses O(n) single-pass algorithm with chronological processing
func calculateDustStack(bets []models.Bet) int64 {
	if len(bets) == 0 {
		return 0
	}

	sortedBets := sortBetsChronologically(bets)

	return calculateDustStackWithCalculator(sortedBets, defaultSellDustCalculator)
}

// GetMarketDustWithCalculator allows callers to supply a custom dust calculator.
// Falls back to default dust behavior if a nil calculator is provided.
func GetMarketDustWithCalculator(bets []models.Bet, calculator SellDustCalculator) int64 {
	if calculator == nil {
		calculator = defaultSellDustCalculator
	}
	return calculateDustStackWithCalculator(sortBetsChronologically(bets), calculator)
}

func calculateDustStackWithCalculator(bets []models.Bet, calculator SellDustCalculator) int64 {
	if calculator == nil {
		return 0
	}

	var totalDust int64
	for _, bet := range bets {
		if bet.Amount >= 0 {
			continue
		}
		totalDust += calculator.DustForSell(bet, bets)
	}
	return totalDust
}

// calculateDustForSell determines dust generated by a specific sell transaction
// This is a placeholder implementation - actual dust calculation will depend on
// the selling mechanism and how shares are valued at the time of sale
func calculateDustForSell(sellBet models.Bet, allBets []models.Bet) int64 {
	return defaultSellDustCalculator.DustForSell(sellBet, allBets)
}

// GetMarketDust calculates accumulated dust for a market
// This is a utility function for dust-related calculations
func GetMarketDust(bets []models.Bet) int64 {
	return calculateDustStack(bets)
}

func sortBetsChronologically(bets []models.Bet) []models.Bet {
	sortedBets := make([]models.Bet, len(bets))
	copy(sortedBets, bets)
	sort.Slice(sortedBets, func(i, j int) bool {
		return sortedBets[i].PlacedAt.Before(sortedBets[j].PlacedAt)
	})
	return sortedBets
}

package positionsmath

import (
	"sort"
	"time"

	marketmath "socialpredict/internal/domain/math/market"
	"socialpredict/internal/domain/math/outcomes/dbpm"
	"socialpredict/internal/domain/math/probabilities/wpam"
	"socialpredict/models"
)

// holds the number of YES and NO shares owned by all users in a market
type MarketPosition struct {
	Username         string `json:"username"`
	MarketID         uint   `json:"marketId"`
	NoSharesOwned    int64  `json:"noSharesOwned"`
	YesSharesOwned   int64  `json:"yesSharesOwned"`
	Value            int64  `json:"value"`
	TotalSpent       int64  `json:"totalSpent"`       // Total amount user spent in this market
	TotalSpentInPlay int64  `json:"totalSpentInPlay"` // Amount spent in unresolved markets only
	IsResolved       bool   `json:"isResolved"`       // From market.IsResolved
	ResolutionResult string `json:"resolutionResult"` // From market.ResolutionResult
}

// UserMarketPosition holds the number of YES and NO shares owned by a user in a market.
type UserMarketPosition struct {
	NoSharesOwned    int64  `json:"noSharesOwned"`
	YesSharesOwned   int64  `json:"yesSharesOwned"`
	Value            int64  `json:"value"`
	TotalSpent       int64  `json:"totalSpent"`
	TotalSpentInPlay int64  `json:"totalSpentInPlay"`
	IsResolved       bool   `json:"isResolved"`
	ResolutionResult string `json:"resolutionResult"`
}

// MarketSnapshot captures the minimal market context needed for position calculations.
type MarketSnapshot struct {
	ID               int64
	CreatedAt        time.Time
	IsResolved       bool
	ResolutionResult string
}

// ProbabilityProvider abstracts probability timeline calculations.
type ProbabilityProvider interface {
	Calculate(createdAt time.Time, bets []models.Bet) []wpam.ProbabilityChange
	Current(changes []wpam.ProbabilityChange) float64
}

// PayoutModel defines how to compute market positions and payouts.
type PayoutModel interface {
	DivideShares(bets []models.Bet, probabilityChanges []wpam.ProbabilityChange) (int64, int64)
	CoursePayouts(bets []models.Bet, probabilityChanges []wpam.ProbabilityChange) []dbpm.CourseBetPayout
	NormalizationFactors(yesShares, noShares int64, coursePayouts []dbpm.CourseBetPayout) (float64, float64)
	ScaledPayouts(bets []models.Bet, coursePayouts []dbpm.CourseBetPayout, yesFactor, noFactor float64) []int64
	AdjustFinalPayouts(bets []models.Bet, scaledPayouts []int64) []int64
	AggregateUserPayouts(bets []models.Bet, finalPayouts []int64) []dbpm.DBPMMarketPosition
	NetAggregateMarketPositions(positions []dbpm.DBPMMarketPosition) []dbpm.DBPMMarketPosition
}

// PositionCalculator encapsulates dependencies used to compute positions.
type PositionCalculator struct {
	probabilities ProbabilityProvider
	payouts       PayoutModel
}

// PositionCalculatorOption configures calculator strategies.
type PositionCalculatorOption func(*PositionCalculator)

// WithProbabilityProvider overrides the probability provider.
func WithProbabilityProvider(p ProbabilityProvider) PositionCalculatorOption {
	return func(c *PositionCalculator) {
		if p != nil {
			c.probabilities = p
		}
	}
}

// WithPayoutModel overrides the payout model.
func WithPayoutModel(p PayoutModel) PositionCalculatorOption {
	return func(c *PositionCalculator) {
		if p != nil {
			c.payouts = p
		}
	}
}

// NewPositionCalculator creates a calculator with default WPAM/DBPM components.
func NewPositionCalculator(opts ...PositionCalculatorOption) PositionCalculator {
	calc := PositionCalculator{
		probabilities: defaultProbabilityProvider{calculator: wpam.NewProbabilityCalculator(nil)},
		payouts:       defaultPayoutModel{},
	}
	for _, opt := range opts {
		opt(&calc)
	}
	calc.ensureDefaults()
	return calc
}

func (c *PositionCalculator) ensureDefaults() {
	if c.probabilities == nil {
		c.probabilities = defaultProbabilityProvider{calculator: wpam.NewProbabilityCalculator(nil)}
	}
	if c.payouts == nil {
		c.payouts = defaultPayoutModel{}
	}
}

// CalculateMarketPositions_WPAM_DBPM summarizes positions for a given market using WPAM/DBPM math.
func CalculateMarketPositions_WPAM_DBPM(snapshot MarketSnapshot, bets []models.Bet) ([]MarketPosition, error) {
	return NewPositionCalculator().CalculateMarketPositions(snapshot, bets)
}

// CalculateMarketPositions runs the position calculation using the calculator's injected strategies.
func (c PositionCalculator) CalculateMarketPositions(snapshot MarketSnapshot, bets []models.Bet) ([]MarketPosition, error) {
	c.ensureDefaults()
	probabilities := c.probabilities
	payouts := c.payouts

	marketIDUint := uint(snapshot.ID)

	sortedBets := sortBetsChronologically(bets)

	allProbabilityChangesOnMarket := probabilities.Calculate(snapshot.CreatedAt, sortedBets)
	netPositions := c.calculateNetPositionsWith(payouts, sortedBets, allProbabilityChangesOnMarket)

	userPositionMap := mapUserPositions(netPositions)
	currentProbability := probabilities.Current(allProbabilityChangesOnMarket)
	totalVolume := marketmath.GetMarketVolume(sortedBets)
	earliestBets := computeEarliestBets(sortedBets)

	valuations, err := CalculateRoundedUserValuationsFromUserMarketPositions(
		userPositionMap,
		currentProbability,
		totalVolume,
		snapshot.IsResolved,
		snapshot.ResolutionResult,
		earliestBets,
	)
	if err != nil {
		return nil, err
	}

	userBetTotals := aggregateUserBetTotals(sortedBets, snapshot.IsResolved)
	displayPositions := assembleDisplayPositions(netPositions, valuations, userBetTotals, snapshot, marketIDUint)

	return displayPositions, nil
}

func computeEarliestBets(bets []models.Bet) map[string]time.Time {
	earliest := make(map[string]time.Time)
	for _, bet := range bets {
		if existing, ok := earliest[bet.Username]; !ok || bet.PlacedAt.Before(existing) {
			earliest[bet.Username] = bet.PlacedAt
		}
	}
	return earliest
}

func sortBetsChronologically(bets []models.Bet) []models.Bet {
	sortedBets := make([]models.Bet, len(bets))
	copy(sortedBets, bets)
	sort.Slice(sortedBets, func(i, j int) bool {
		return sortedBets[i].PlacedAt.Before(sortedBets[j].PlacedAt)
	})
	return sortedBets
}

func calculateNetPositions(sortedBets []models.Bet, probabilityChanges []wpam.ProbabilityChange) []dbpm.DBPMMarketPosition {
	return NewPositionCalculator().calculateNetPositions(sortedBets, probabilityChanges)
}

func (c PositionCalculator) calculateNetPositions(sortedBets []models.Bet, probabilityChanges []wpam.ProbabilityChange) []dbpm.DBPMMarketPosition {
	c.ensureDefaults()
	payouts := c.payouts
	return c.calculateNetPositionsWith(payouts, sortedBets, probabilityChanges)
}

func (c PositionCalculator) calculateNetPositionsWith(payouts PayoutModel, sortedBets []models.Bet, probabilityChanges []wpam.ProbabilityChange) []dbpm.DBPMMarketPosition {
	S_YES, S_NO := payouts.DivideShares(sortedBets, probabilityChanges)
	coursePayouts := payouts.CoursePayouts(sortedBets, probabilityChanges)
	F_YES, F_NO := payouts.NormalizationFactors(S_YES, S_NO, coursePayouts)
	scaledPayouts := payouts.ScaledPayouts(sortedBets, coursePayouts, F_YES, F_NO)
	finalPayouts := payouts.AdjustFinalPayouts(sortedBets, scaledPayouts)
	aggreatedPositions := payouts.AggregateUserPayouts(sortedBets, finalPayouts)
	return payouts.NetAggregateMarketPositions(aggreatedPositions)
}

func mapUserPositions(netPositions []dbpm.DBPMMarketPosition) map[string]UserMarketPosition {
	userPositionMap := make(map[string]UserMarketPosition)
	for _, p := range netPositions {
		userPositionMap[p.Username] = UserMarketPosition{
			YesSharesOwned: p.YesSharesOwned,
			NoSharesOwned:  p.NoSharesOwned,
		}
	}
	return userPositionMap
}

func aggregateUserBetTotals(sortedBets []models.Bet, isResolved bool) map[string]struct {
	TotalSpent       int64
	TotalSpentInPlay int64
} {
	userBetTotals := make(map[string]struct {
		TotalSpent       int64
		TotalSpentInPlay int64
	})

	for _, bet := range sortedBets {
		totals := userBetTotals[bet.Username]
		totals.TotalSpent += bet.Amount
		if !isResolved {
			totals.TotalSpentInPlay += bet.Amount
		}
		userBetTotals[bet.Username] = totals
	}
	return userBetTotals
}

func assembleDisplayPositions(
	netPositions []dbpm.DBPMMarketPosition,
	valuations map[string]UserValuationResult,
	userBetTotals map[string]struct {
		TotalSpent       int64
		TotalSpentInPlay int64
	},
	snapshot MarketSnapshot,
	marketIDUint uint,
) []MarketPosition {
	var (
		displayPositions []MarketPosition
		seenUsers        = make(map[string]bool)
	)

	for _, p := range netPositions {
		val := valuations[p.Username]
		betTotals := userBetTotals[p.Username]
		displayPositions = append(displayPositions, MarketPosition{
			Username:         p.Username,
			MarketID:         marketIDUint,
			YesSharesOwned:   p.YesSharesOwned,
			NoSharesOwned:    p.NoSharesOwned,
			Value:            val.RoundedValue,
			TotalSpent:       betTotals.TotalSpent,
			TotalSpentInPlay: betTotals.TotalSpentInPlay,
			IsResolved:       snapshot.IsResolved,
			ResolutionResult: snapshot.ResolutionResult,
		})
		seenUsers[p.Username] = true
	}

	for username, totals := range userBetTotals {
		if seenUsers[username] {
			continue
		}

		displayPositions = append(displayPositions, MarketPosition{
			Username:         username,
			MarketID:         marketIDUint,
			YesSharesOwned:   0,
			NoSharesOwned:    0,
			Value:            valuations[username].RoundedValue,
			TotalSpent:       totals.TotalSpent,
			TotalSpentInPlay: totals.TotalSpentInPlay,
			IsResolved:       snapshot.IsResolved,
			ResolutionResult: snapshot.ResolutionResult,
		})
	}

	return displayPositions
}

// CalculateMarketPositionForUser_WPAM_DBPM fetches and summarizes the position for a given user in a specific market.
func CalculateMarketPositionForUser_WPAM_DBPM(snapshot MarketSnapshot, bets []models.Bet, username string) (UserMarketPosition, error) {
	marketPositions, err := CalculateMarketPositions_WPAM_DBPM(snapshot, bets)
	if err != nil {
		return UserMarketPosition{}, err
	}

	for _, position := range marketPositions {
		if position.Username == username {
			return UserMarketPosition{
				NoSharesOwned:    position.NoSharesOwned,
				YesSharesOwned:   position.YesSharesOwned,
				Value:            position.Value,
				TotalSpent:       position.TotalSpent,
				TotalSpentInPlay: position.TotalSpentInPlay,
				IsResolved:       position.IsResolved,
				ResolutionResult: position.ResolutionResult,
			}, nil
		}
	}

	return UserMarketPosition{}, nil
}

// CalculateAllUserMarketPositions_WPAM_DBPM is deprecated. Prefer computing positions via
// CalculateMarketPositions_WPAM_DBPM after fetching market snapshots and bet histories from a repository.

package dbpm

import (
	"math"
	marketmath "socialpredict/internal/domain/math/market"
	"socialpredict/internal/domain/math/probabilities/wpam"
	"socialpredict/models"
)

const (
	dbpmOutcomeYes = "YES"
	dbpmOutcomeNo  = "NO"
)

type poolShareWeight func(probability float64) float64
type normalizationAccumulator func(*normalizationSums, float64)
type normalizationFactorSelector func(normalizationFactors) float64
type payoutAggregator func(*DBPMMarketPosition, int64)
type exposureAccumulator func(*sideExposure, int64)

type normalizationSums struct {
	yes float64
	no  float64
}

type normalizationFactors struct {
	yes float64
	no  float64
}

type sideExposure struct {
	yes int64
	no  int64
}

var dbpmPoolShareWeights = map[string]poolShareWeight{
	dbpmOutcomeYes: func(probability float64) float64 { return probability },
	dbpmOutcomeNo:  func(probability float64) float64 { return 1 - probability },
}

var dbpmNormalizationAccumulators = map[string]normalizationAccumulator{
	dbpmOutcomeYes: func(sums *normalizationSums, payout float64) { sums.yes += payout },
	dbpmOutcomeNo:  func(sums *normalizationSums, payout float64) { sums.no += payout },
}

var dbpmNormalizationSelectors = map[string]normalizationFactorSelector{
	dbpmOutcomeYes: func(factors normalizationFactors) float64 { return factors.yes },
	dbpmOutcomeNo:  func(factors normalizationFactors) float64 { return factors.no },
}

var dbpmPayoutAggregators = map[string]payoutAggregator{
	dbpmOutcomeYes: func(position *DBPMMarketPosition, payout int64) { position.YesSharesOwned += payout },
	dbpmOutcomeNo:  func(position *DBPMMarketPosition, payout int64) { position.NoSharesOwned += payout },
}

var dbpmExposureAccumulators = map[string]exposureAccumulator{
	dbpmOutcomeYes: func(exposure *sideExposure, amount int64) { exposure.yes += amount },
	dbpmOutcomeNo:  func(exposure *sideExposure, amount int64) { exposure.no += amount },
}

// holds betting payout information
type CourseBetPayout struct {
	Payout  float64
	Outcome string
}

type DBPMMarketPosition struct {
	Username       string
	NoSharesOwned  int64
	YesSharesOwned int64
}

// DivideUpMarketPoolSharesDBPM divides the market pool into YES and NO pools based on the resolution probability.
// See README/README-MATH-PROB-AND-PAYOUT.md#market-outcome-update-formulae---divergence-based-payout-model-dbpm
func DivideUpMarketPoolSharesDBPM(bets []models.Bet, probabilityChanges []wpam.ProbabilityChange) (int64, int64) {
	if len(probabilityChanges) == 0 {
		return 0, 0
	}

	// Get the last probability change, which is the resolution probability
	currentProbability := wpam.GetCurrentProbability(probabilityChanges)

	// Get the total share pool as a float for precision
	// Do not include the initial market subsidization in volume until market hits final resolution
	totalSharePool := float64(marketmath.GetMarketVolume(bets))

	// Initial condition, shares set to zero
	yesShares := int64(0)
	noShares := int64(0)

	// Check case where there is only one bet
	if marketmath.GetMarketVolume(bets) == 1 {
		yesShares, noShares = singleCreditYesNoAllocator(bets)
	} else {
		yesShares, noShares = dividePoolShares(totalSharePool, currentProbability)
	}

	// Return calculated shares
	return yesShares, noShares
}

func dividePoolShares(totalSharePool, probability float64) (int64, int64) {
	var totals sideExposure
	for outcome, weight := range dbpmPoolShareWeights {
		allocateExposure(&totals, outcome, int64(math.Round(totalSharePool*weight(probability))))
	}
	return totals.yes, totals.no
}

// CalculateCoursePayoutsDBPM calculates the course payout for each bet in the market,
// separating the payouts for YES and NO outcomes.
// See README/README-MATH-PROB-AND-PAYOUT.md#market-outcome-update-formulae---divergence-based-payout-model-dbpm
func CalculateCoursePayoutsDBPM(bets []models.Bet, probabilityChanges []wpam.ProbabilityChange) []CourseBetPayout {
	if len(probabilityChanges) == 0 {
		return nil
	}

	var coursePayouts []CourseBetPayout

	// Get the current (final) probability for the market
	currentProbability := probabilityChanges[len(probabilityChanges)-1].Probability

	// Iterate over each bet to calculate its course payout
	for i, bet := range bets {
		// Probability at which the bet was placed is the bet index+1
		// The probability index is always the length of the bet index+1 because of the initial probability
		betProbabilityAtTimePlaced := probabilityChanges[i+1].Probability

		coursePaymentForBet := math.Abs(currentProbability-betProbabilityAtTimePlaced) * float64(bet.Amount)

		// Append the calculated payout to the result
		coursePayouts = append(coursePayouts, CourseBetPayout{Payout: coursePaymentForBet, Outcome: bet.Outcome})
	}

	return coursePayouts
}

// F_YES calculates the normalization factor for "YES" by dividing the total stake by the cumulative payout for "YES".
// F_NO calculates the normalization factor for "NO" by dividing the total stake by the cumulative payout for "NO".
// Return absolute values of normalization factors to ensure non-negative values for further calculations.
func CalculateNormalizationFactorsDBPM(yesShares int64, noShares int64, coursePayouts []CourseBetPayout) (float64, float64) {
	var payoutSums normalizationSums
	for _, payout := range coursePayouts {
		accumulateNormalizationPayout(&payoutSums, payout)
	}

	return normalizationFactor(yesShares, payoutSums.yes), normalizationFactor(noShares, payoutSums.no)
}

// CalculateFinalPayouts calculates the final payouts for each bet, adjusted by normalization factors.
func CalculateScaledPayoutsDBPM(allBetsOnMarket []models.Bet, coursePayouts []CourseBetPayout, yesNormalizationFactor, noNormalizationFactor float64) []int64 {
	scaledPayouts := make([]int64, len(allBetsOnMarket))
	factors := normalizationFactors{yes: yesNormalizationFactor, no: noNormalizationFactor}

	for i, payout := range coursePayouts {
		scaledPayouts[i] = int64(math.Round(scalePayout(payout, factors)))
	}

	return scaledPayouts
}

// calculateExcess determines the amount of credits unaccounted for by comparing calculated scaledPayouts to availablePool
func calculateExcess(bets []models.Bet, scaledPayouts []int64) int64 {
	var sumScaledPayouts int64
	for _, payout := range scaledPayouts {
		sumScaledPayouts += payout
	}
	availablePool := marketmath.GetMarketVolume(bets)
	return sumScaledPayouts - availablePool
}

// Adjust scaled payouts if excess is greater than 0
// This  should not be possible given how the preceeding pipeline works, but we adjust for it anyway.
func adjustForPositiveExcess(scaledPayouts []int64, excess int64) []int64 {
	// No adjustment needed if no payouts or excess is non-positive
	if excess <= 0 || len(scaledPayouts) == 0 {
		return scaledPayouts
	}

	numBets := int64(len(scaledPayouts)) // Total number of bets
	absoluteExcess := excess             // No need to negate since it's already positive

	// Calculate the base reduction for each bet and the leftover remainder
	baseReduction := absoluteExcess / numBets
	totalReduction := baseReduction * numBets
	remainderReduction := absoluteExcess - totalReduction

	// Apply the base reduction to all payouts
	for betIndex := range scaledPayouts {
		scaledPayouts[betIndex] -= baseReduction
	}

	// Apply the remainder reduction to the newest bets
	for betIndex := int64(len(scaledPayouts)) - 1; remainderReduction > 0; betIndex-- {
		scaledPayouts[betIndex] -= 1
		remainderReduction--
	}

	return scaledPayouts
}

func adjustForNegativeExcess(scaledPayouts []int64, excess int64) []int64 {
	// No adjustment needed if no payouts or excess is non-negative
	if excess >= 0 || len(scaledPayouts) == 0 {
		return scaledPayouts
	}

	numBets := int64(len(scaledPayouts)) // Total number of bets
	absoluteExcess := -excess            // Convert excess to positive for allocation

	// Calculate the base addition for each bet and the leftover remainder
	// int64 will apply floor division
	baseAddition := int64(absoluteExcess / numBets)
	totalAddition := baseAddition * numBets
	remainderAddition := absoluteExcess - totalAddition

	// Apply the base addition to all payouts
	for betIndex := range scaledPayouts {
		scaledPayouts[betIndex] += baseAddition
	}

	// Apply the remainder addition to the earliest bets
	for betIndex := int64(0); betIndex < remainderAddition; betIndex++ {
		scaledPayouts[betIndex] += 1
	}

	return scaledPayouts
}

// AdjustPayouts reconciles the additional or lacking funds from the betting pool by adjusting the payouts to past bets
func AdjustPayouts(bets []models.Bet, scaledPayouts []int64) []int64 {
	excess := calculateExcess(bets, scaledPayouts)

	if excess > 0 {
		scaledPayouts = adjustForPositiveExcess(scaledPayouts, excess)
	} else if excess < 0 {
		scaledPayouts = adjustForNegativeExcess(scaledPayouts, excess)
	}

	return scaledPayouts
}

// AggregateUserPayouts aggregates YES and NO payouts for each user.
func AggregateUserPayoutsDBPM(bets []models.Bet, finalPayouts []int64) []DBPMMarketPosition {
	userPayouts := make(map[string]*DBPMMarketPosition)

	for i, bet := range bets {
		payout := finalPayouts[i]

		// Initialize the user's market position if it doesn't exist
		if _, exists := userPayouts[bet.Username]; !exists {
			userPayouts[bet.Username] = &DBPMMarketPosition{Username: bet.Username}
		}

		aggregatePositionByOutcome(userPayouts[bet.Username], bet.Outcome, payout)
	}

	// Convert map to slice for output
	var positions []DBPMMarketPosition
	for _, pos := range userPayouts {
		// Check and adjust negative shares to 0
		if pos.YesSharesOwned < 0 {
			pos.YesSharesOwned = 0
		}
		if pos.NoSharesOwned < 0 {
			pos.NoSharesOwned = 0
		}
		positions = append(positions, *pos)
	}

	return positions
}

// Function to normalize market positions such that for each user,
// only one of YesSharesOwned or NoSharesOwned is greater than 0,
// with the other being 0, and the value is the net difference.
func NetAggregateMarketPositions(positions []DBPMMarketPosition) []DBPMMarketPosition {
	var normalizedPositions []DBPMMarketPosition

	for _, position := range positions {
		var normalizedPosition DBPMMarketPosition
		normalizedPosition.Username = position.Username

		if position.YesSharesOwned > position.NoSharesOwned {
			normalizedPosition.YesSharesOwned = position.YesSharesOwned - position.NoSharesOwned
			normalizedPosition.NoSharesOwned = 0
		} else {
			normalizedPosition.NoSharesOwned = position.NoSharesOwned - position.YesSharesOwned
			normalizedPosition.YesSharesOwned = 0
		}

		normalizedPositions = append(normalizedPositions, normalizedPosition)
	}

	return normalizedPositions
}

// SingleCreditYesNoAllocator assigns the remaining credit/share to YES or NO, based on net position.
func singleCreditYesNoAllocator(bets []models.Bet) (yesShares int64, noShares int64) {
	var exposure sideExposure
	for _, bet := range bets {
		allocateExposure(&exposure, bet.Outcome, bet.Amount)
	}
	if exposure.yes > exposure.no {
		return 1, 0
	} else if exposure.no > exposure.yes {
		return 0, 1
	}
	// If equal or ambiguous, assign to neither (fallback)
	return 0, 0
}

func accumulateNormalizationPayout(sums *normalizationSums, payout CourseBetPayout) {
	if accumulator, ok := dbpmNormalizationAccumulators[payout.Outcome]; ok {
		accumulator(sums, payout.Payout)
	}
}

func normalizationFactor(shares int64, payoutSum float64) float64 {
	if payoutSum <= 0 {
		return 0
	}
	return math.Abs(float64(shares) / payoutSum)
}

func scalePayout(payout CourseBetPayout, factors normalizationFactors) float64 {
	selector, ok := dbpmNormalizationSelectors[payout.Outcome]
	if !ok {
		return 0
	}
	return payout.Payout * selector(factors)
}

func aggregatePositionByOutcome(position *DBPMMarketPosition, outcome string, payout int64) {
	if aggregate, ok := dbpmPayoutAggregators[outcome]; ok {
		aggregate(position, payout)
	}
}

